_gate_allocation_db/intl_gate_rules.rs.xml','intl_gate_rules.rs.xml',0,NULL,'<?xml version=\"1.0\" encoding=\"utf-8\"?>\n<rule-set>\n  <import-variable-library path=\"dbr:/airport_gate_allocation_db/flight_info.vl.xml\"/>\n  <import-variable-library path=\"dbr:/airport_gate_allocation_db/gate_result.vl.xml\"/>\n  <import-parameter-library path=\"dbr:/airport_gate_allocation_db/canshu0.pl.xml\"/>\n  <rule name=\"国际航班近机位\" salience=\"10\">\n    <if><and>\n      <atom op=\"Equals\">\n        <left var-category=\"FlightInfo\" var=\"is_international\" var-label=\"is_international\" datatype=\"Boolean\"/>\n        <value content=\"true\" type=\"Input\"/>\n      </atom>\n    </and></if>\n    <then>\n      <var-assign var-category=\"GateResult\" var=\"gate_type\" var-label=\"gate_type\" datatype=\"String\"><value content=\"近机位\" type=\"Input\"/></var-assign>\n      <var-assign var-category=\"GateResult\" var=\"reason\" var-label=\"reason\" datatype=\"String\"><value content=\"国际航班优先分配近机位\" type=\"Input\"/></var-assign>\n    </then>\n  </rule>\n  <rule name=\"国内航班远机位\" salience=\"1\">\n    <if><and>\n      <atom op=\"Equals\">\n        <left var-category=\"FlightInfo\" var=\"is_international\" var-label=\"is_international\" datatype=\"Boolean\"/>\n        <value content=\"false\" type=\"Input\"/>\n      </atom>\n    </and></if>\n    <then>\n      <var-assign var-category=\"GateResult\" var=\"gate_type\" var-label=\"gate_type\" datatype=\"String\"><value content=\"远机位\" type=\"Input\"/></var-assign>\n      <var-assign var-category=\"GateResult\" var=\"reason\" var-label=\"reason\" datatype=\"String\"><value content=\"国内航班默认远机位\" type=\"Input\"/></var-assign>\n    </then>\n  </rule>\n</rule-set>','admin','admin',NULL,1774629279000,1774630091000,NULL,NULL),(201,'airport_gate_allocation_db','/airport_gate_allocation_db/rea_time_rules.rea.xml','rea_time_rules.rea.xml',0,NULL,'<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<rule-set>\n  <import-variable-library path=\"dbr:/airport_gate_allocation_db/flight_info.vl.xml\"/>\n  <import-variable-library path=\"dbr:/airport_gate_allocation_db/gate_result.vl.xml\"/>\n  <import-parameter-library path=\"dbr:/airport_gate_allocation_db/canshu0.pl.xml\"/>\n  <import-parameter-library path=\"dbr:/airport_gate_allocation_db/canshu1.pl.xml\"/>\n  <rule name=\"高峰时段大客流近机位\">\n    <if>\n  <and>\n    <atom op=\"GreaterThenEquals\">\n      <left var-category=\"FlightInfo\" var=\"arrival_time\" var-label=\"arrival_time\" datatype=\"Integer\" type=\"variable\">\n      </left>\n      <value content=\"7\" type=\"Input\"/>\n    </atom>\n    <atom op=\"LessThenEquals\">\n      <left var-category=\"FlightInfo\" var=\"arrival_time\" var-label=\"arrival_time\" datatype=\"Integer\" type=\"variable\">\n      </left>\n      <value content=\"9\" type=\"Input\"/>\n    </atom>\n    <atom op=\"GreaterThen\">\n      <left var-category=\"FlightInfo\" var=\"passenger_count\" var-label=\"passenger_count\" datatype=\"Integer\" type=\"variable\">\n      </left>\n      <value content=\"100\" type=\"Input\"/>\n    </atom>\n  </and>\n    </if>\n    <then>\n  <var-assign var-category=\"GateResult\" var=\"gate_type\" var-label=\"gate_type\" datatype=\"String\" type=\"variable\">\n    <value content=\"近机位\" type=\"Input\"/>\n  </var-assign>\n  <var-assign var=\"can_reason\" var-label=\"can_reason_reason\" datatype=\"String\" type=\"parameter\">\n    <value content=\"高峰时段大客流优先近机位\" type=\"Input\"/>\n  </var-assign>\n  <var-assign var=\"can_score\" var-label=\"can_score_title\" datatype=\"Integer\" type=\"parameter\">\n    <value content=\"80\" type=\"Input\"/>\n  </var-assign>\n    </then>\n  </rule>\n  <rule name=\"低峰时段默认远机位\">\n    <if>\n  <and>\n    <atom op=\"GreaterThen\">\n      <left var-category=\"FlightInfo\" var=\"arrival_time\" var-label=\"arrival_time\" datatype=\"Integer\" type=\"variable\">\n      </left>\n      <value content=\"22\" type=\"Input\"/>\n    </atom>\n  </and>\n    </if>\n    <then>\n  <var-assign var-category=\"GateResult\" var=\"gate_type\" var-label=\"gate_type\" datatype=\"String\" type=\"variable\">\n    <value content=\"远机位\" type=\"Input\"/>\n  </var-assign>\n  <var-assign var=\"can_reason\" var-label=\"can_reason_reason\" datatype=\"String\" type=\"parameter\">\n    <value content=\"低峰时段默认远机位\" type=\"Input\"/>\n  </var-assign>\n  <var-assign var=\"can_score\" var-label=\"can_score_title\" datatype=\"Integer\" type=\"parameter\">\n    <value content=\"20\" type=\"Input\"/>\n  </var-assign>\n    </then>\n  </rule>\n</rule-set>','admin','admin',NULL,1774629300000,1774704949783,NULL,NULL),(202,'airport_gate_allocation_db','/airport_gate_allocation_db/aircraft_gate_map.dt.xml','aircraft_gate_map.dt.xml',0,NULL,'<decision-table><remark><![CDATA[]]></remark><import-variable-library path=\"dbr:/airport_gate_allocation_db/flight_info.vl.xml\"/><import-variable-library path=\"dbr:/airport_gate_allocation_db/gate_result.vl.xml\"/><cell row=\"0\" col=\"0\" rowspan=\"1\"><joint type=\"and\"><condition op=\"Equals\"><value  content=\"B737\" type=\"Input\" ></value></condition></joint></cell><cell row=\"0\" col=\"1\" rowspan=\"1\"><joint type=\"and\"><condition op=\"Equals\"><value  content=\"false\" type=\"Input\" ></value></condition></joint></cell><cell row=\"1\" col=\"0\" rowspan=\"1\"><joint type=\"and\"><condition op=\"Equals\"><value  content=\"A320\" type=\"Input\" ></value></condition></joint></cell><cell row=\"0\" col=\"2\" rowspan=\"1\"><value  content=\"A区-101\" type=\"Input\" ></value></cell><cell row=\"1\" col=\"1\" rowspan=\"1\"><joint type=\"and\"><condition op=\"Equals\"><value  content=\"false\" type=\"Input\" ></value></condition></joint></cell><cell row=\"2\" col=\"0\" rowspan=\"1\"><joint type=\"and\"><condition op=\"Equals\"><value  content=\"B777\" type=\"Input\" ></value></condition></joint></cell><cell row=\"1\" col=\"2\" rowspan=\"1\"><value  content=\"A区-102\" type=\"Input\" ></value></cell><cell row=\"2\" col=\"1\" rowspan=\"1\"><joint type=\"and\"><con