db','/airport_gate_allocation_db/common_libs','common_libs',1,'lib',NULL,'admin','admin',NULL,1774755798000,1774755798000,NULL,NULL),(217,'airport_gate_allocation_db','/airport_gate_allocation_db/common_libs/shared_vars.vl.xml','shared_vars.vl.xml',0,NULL,'<?xml version=\"1.0\" encoding=\"utf-8\"?>\n<variable-library>\n  <category name=\"SharedVars\" clazz=\"SharedVars\" type=\"GeneralEntity\">\n    <var name=\"debug_mode\" label=\"debug_mode\" type=\"Boolean\" act=\"InOut\"/>\n  </category>\n</variable-library>','admin','admin',NULL,1774755798000,1774755798000,NULL,NULL),(218,'airport_gate_allocation_db','/airport_gate_allocation_db/intl_rules/asia/asia_peak_rules.rea.xml','asia_peak_rules.rea.xml',0,NULL,'<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<rule-set>\n  <import-variable-library path=\"dbr:/airport_gate_allocation_db/flight_info.vl.xml\"/>\n  <import-variable-library path=\"dbr:/airport_gate_allocation_db/gate_result.vl.xml\"/>\n  <import-parameter-library path=\"dbr:/airport_gate_allocation_db/canshu0.pl.xml\"/>\n  <rule name=\"亚洲高峰大客流\">\n    <if>\n      <and>\n        <atom op=\"GreaterThenEquals\">\n          <left var-category=\"FlightInfo\" var=\"arrival_time\" var-label=\"arrival_time\" datatype=\"Integer\" type=\"variable\"/>\n          <value content=\"6\" type=\"Input\"/>\n        </atom>\n        <atom op=\"LessThenEquals\">\n          <left var-category=\"FlightInfo\" var=\"arrival_time\" var-label=\"arrival_time\" datatype=\"Integer\" type=\"variable\"/>\n          <value content=\"10\" type=\"Input\"/>\n        </atom>\n        <atom op=\"Equals\">\n          <left var-category=\"FlightInfo\" var=\"is_international\" var-label=\"is_international\" datatype=\"Boolean\" type=\"variable\"/>\n          <value content=\"true\" type=\"Input\"/>\n        </atom>\n        <atom op=\"GreaterThen\">\n          <left var-category=\"FlightInfo\" var=\"passenger_count\" var-label=\"passenger_count\" datatype=\"Integer\" type=\"variable\"/>\n          <value content=\"180\" type=\"Input\"/>\n        </atom>\n      </and>\n    </if>\n    <then>\n      <var-assign var-category=\"GateResult\" var=\"gate_type\" var-label=\"gate_type\" datatype=\"String\"><value content=\"近机位\" type=\"Input\"/></var-assign>\n      <var-assign var-category=\"GateResult\" var=\"assigned_gate\" var-label=\"assigned_gate\" datatype=\"String\"><value content=\"B区-205\" type=\"Input\"/></var-assign>\n      <var-assign var-category=\"GateResult\" var=\"reason\" var-label=\"reason\" datatype=\"String\"><value content=\"亚洲高峰时段大客流近机位\" type=\"Input\"/></var-assign>\n    </then>\n  </rule>\n  <rule name=\"亚洲低峰默认\">\n    <if>\n      <and>\n        <atom op=\"GreaterThen\">\n          <left var-category=\"FlightInfo\" var=\"arrival_time\" var-label=\"arrival_time\" datatype=\"Integer\" type=\"variable\"/>\n          <value content=\"22\" type=\"Input\"/>\n        </atom>\n        <atom op=\"Equals\">\n          <left var-category=\"FlightInfo\" var=\"is_international\" var-label=\"is_international\" datatype=\"Boolean\" type=\"variable\"/>\n          <value content=\"true\" type=\"Input\"/>\n        </atom>\n      </and>\n    </if>\n    <then>\n      <var-assign var-category=\"GateResult\" var=\"gate_type\" var-label=\"gate_type\" datatype=\"String\"><value content=\"远机位\" type=\"Input\"/></var-assign>\n      <var-assign var-category=\"GateResult\" var=\"reason\" var-label=\"reason\" datatype=\"String\"><value content=\"亚洲低峰时段远机位\" type=\"Input\"/></var-assign>\n    </then>\n  </rule>\n</rule-set>','admin','admin',NULL,1774756333000,1774756333000,NULL,NULL);

